1	// Program-data validators. Cross-checks every workout exercise reference
2	// against the source-of-truth exercise catalog so a program cannot ship with
3	// unknown exercise_ids. Mobility / principles enforcement remains load-bearing
4	// for the workout app's safety philosophy (mobility-first, injury-prevention).
5	
6	import type { Program } from '../tabs/Workouts/types';
7	import type { ExerciseCatalog } from '../data/types';
8	import type { EquipmentKind } from '../data/equipmentCatalog';
9	
10	export interface Finding {
11	  path: string;
12	  message: string;
13	}
14	
15	// User inventory shape — PR-B owns the actual storage; this is just the
16	// minimum shape needed for cross-check here.
17	export type InventoryView = Partial<Record<EquipmentKind, { ownedWeights: number[] }>>;
18	
19	export interface ValidationResult {
20	  ok: boolean;
21	  errors: Finding[];
22	  warnings?: Finding[];
23	}
24	
25	export const REQUIRED_PRINCIPLES = [
26	  'injury_prevention',
27	  'mobility_every_phase',
28	  'form_over_load',
29	  'longevity_focus',
30	] as const;
31	
32	const MOBILITY_KEYWORDS = ['mobility', 'flexibility', 'recovery', 'stretch', 'flow'];
33	
34	function isObject(v: unknown): v is Record<string, unknown> {
35	  return typeof v === 'object' && v !== null && !Array.isArray(v);
36	}
37	
38	function groupCoveredByInventory(
39	  group: EquipmentKind[],
40	  ownedKinds: ReadonlySet<EquipmentKind>,
41	): boolean {
42	  return group.every((k) => k === 'bodyweight' || ownedKinds.has(k));
43	}
44	
45	export function validateProgramSchema(
46	  p: unknown,
47	  catalog: ExerciseCatalog,
48	  inventory?: InventoryView,
49	): ValidationResult {
50	  const errors: Finding[] = [];
51	  const warnings: Finding[] = [];
52	  const ownedKinds: ReadonlySet<EquipmentKind> | null = inventory
53	    ? new Set(Object.keys(inventory) as EquipmentKind[])
54	    : null;
55	
56	  if (!isObject(p)) {
57	    return { ok: false, errors: [{ path: '$', message: 'program must be an object' }] };
58	  }
59	
60	  if (!isObject(p.meta)) {
61	    errors.push({ path: 'meta', message: 'missing meta object' });
62	  } else {
63	    if (typeof p.meta.startDate !== 'string') {
64	      errors.push({ path: 'meta.startDate', message: 'must be a string' });
65	    }
66	    if (typeof p.meta.version !== 'string') {
67	      errors.push({ path: 'meta.version', message: 'must be a string' });
68	    }
69	  }
70	
71	  if (!Array.isArray(p.phases)) {
72	    errors.push({ path: 'phases', message: 'must be an array' });
73	    return ownedKinds
74	      ? { ok: errors.length === 0, errors, warnings }
75	      : { ok: errors.length === 0, errors };
76	  }
77	
78	  p.phases.forEach((phase, i) => {
79	    const prefix = `phases[${i}]`;
80	    if (!isObject(phase)) {
81	      errors.push({ path: prefix, message: 'must be an object' });
82	      return;
83	    }
84	    if (typeof phase.id !== 'string') {
85	      errors.push({ path: `${prefix}.id`, message: 'missing id' });
86	    }
87	    if (typeof phase.name !== 'string') {
88	      errors.push({ path: `${prefix}.name`, message: 'missing name' });
89	    }
90	    if (typeof phase.duration_weeks !== 'number') {
91	      errors.push({
92	        path: `${prefix}.duration_weeks`,
93	        message: 'must be a number',
