// Prompt-assembly helpers. Pure string handling so tests can exercise them
// without going through Vite's ?raw template import.

import type { FilteredCatalog } from './filteredCatalog';
import type { Program } from '../tabs/Workouts/types';

export const RUNTIME_START_MARKER = '<!-- RUNTIME PROMPT START -->';
export const RUNTIME_END_MARKER = '<!-- RUNTIME PROMPT END -->';

// Pulls the section between the markers out of the raw template file. The
// rest of the file (the manual fallback) is documentation and must never be
// sent to the LLM.
export function extractRuntimeSection(raw: string): string {
  const start = raw.indexOf(RUNTIME_START_MARKER);
  const end = raw.indexOf(RUNTIME_END_MARKER);
  if (start < 0 || end < 0 || end < start) {
    throw new Error(
      'generate-phase.md is missing RUNTIME PROMPT START/END markers',
    );
  }
  return raw.slice(start + RUNTIME_START_MARKER.length, end).trim();
}

function escapeForReplacement(value: string): string {
  // String.prototype.replace treats `$` sequences in the replacement string
  // specially. Catalog JSON can contain them in techniqueNote text someday,
  // so neutralize them up front.
  return value.replace(/\$/g, '$$$$');
}

export interface AssemblePromptInput {
  template: string;
  userRequest: string;
  filteredCatalog: FilteredCatalog;
  previousProgram?: Program;
}

export function assemblePrompt(input: AssemblePromptInput): string {
  const runtime = extractRuntimeSection(input.template);
  const catalogJson = JSON.stringify(input.filteredCatalog.exercises, null, 2);
  const previous = input.previousProgram
    ? JSON.stringify(input.previousProgram, null, 2)
    : 'none';
  return runtime
    .replace(/\{\{user_request\}\}/g, escapeForReplacement(input.userRequest))
    .replace(/\{\{filtered_catalog_json\}\}/g, escapeForReplacement(catalogJson))
    .replace(
      /\{\{previous_program_or_none\}\}/g,
      escapeForReplacement(previous),
    );
}

