// AI program-generation orchestrator. Single entry point used by the
// Workouts tab. Wires together:
//   1. Inventory → filtered catalog (only exercises the user can perform).
//   2. Prompt template → assembled prompt with user request + catalog.
//   3. LLM provider call.
//   4. Parse + schema validation (structural errors throw; inventory
//      mismatches surface as warnings).
//
// The provider itself is still stubbed — see src/llm/index.ts. Configuring a
// real provider lands in a later PR. This module is callable today against
// any provider whose generate() returns the program JSON as a string.

import promptTemplateRaw from '../../prompts/generate-phase.md?raw';

import { EXERCISE_CATALOG } from '../data/exerciseCatalog';
import type { Inventory } from '../data/inventory';
import {
  type Finding,
  validateProgramSchema,
} from '../db/programSchema';
import type { Program } from '../tabs/Workouts/types';
import { generate } from './index';
import {
  buildFilteredCatalog,
  type FilteredCatalog,
} from './filteredCatalog';
import { assemblePrompt } from './promptAssembly';

export type { FilteredCatalog, FilteredExercise } from './filteredCatalog';
export { buildFilteredCatalog } from './filteredCatalog';

export interface ProgramGenerationResult {
  program: Program;
  warnings: Finding[];
  filteredCatalog: FilteredCatalog;
}

export interface GenerateProgramOptions {
  inventory: Inventory;
  userRequest: string;
  previousProgram?: Program;
}

function buildResponseSchema(filtered: FilteredCatalog): unknown {
  const exerciseIds = filtered.exercises.map((e) => e.id);
  return {
    type: 'object',
    required: ['meta', 'phases'],
    properties: {
      meta: {
        type: 'object',
        required: ['startDate', 'version', 'principles', 'constraints'],
      },
      phases: {
        type: 'array',
        items: {
          type: 'object',
          required: ['id', 'name', 'duration_weeks', 'workouts'],
          properties: {
            workouts: {
              type: 'object',
              additionalProperties: {
                type: 'object',
                required: ['name', 'focus', 'exercises'],
                properties: {
                  exercises: {
                    type: 'array',
                    items: {
                      type: 'object',
                      required: ['exercise_id', 'sets', 'reps', 'rest'],
                      properties: {
                        exercise_id: { type: 'string', enum: exerciseIds },
                        starting_weight: { type: 'number' },
                      },
                    },
                  },
                },
              },
            },
          },
        },
      },
    },
  };
}

function summarizeErrors(errors: Finding[]): string {
  return errors
    .slice(0, 3)
    .map((e) => `${e.path}: ${e.message}`)
    .join('; ');
}

export async function generateProgram(
  opts: GenerateProgramOptions,
): Promise<ProgramGenerationResult> {
  const filteredCatalog = buildFilteredCatalog(opts.inventory);
  const prompt = assemblePrompt({
    template: promptTemplateRaw,
    userRequest: opts.userRequest,
    filteredCatalog,
    previousProgram: opts.previousProgram,
  });
  const schema = buildResponseSchema(filteredCatalog);

  const result = generate({ prompt, schema });
  const raw = await Promise.resolve(result as Promise<string>);

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    const detail = err instanceof Error ? err.message : 'unknown parse error';
    throw new Error(`AI returned non-JSON: ${detail}`);
  }

  const validation = validateProgramSchema(
    parsed,
    EXERCISE_CATALOG,
    opts.inventory,
  );
  if (!validation.ok) {
    throw new Error(
      `Generated program failed schema validation: ${summarizeErrors(validation.errors)}`,
    );
  }

  return {
    program: parsed as Program,
    warnings: validation.warnings ?? [],
    filteredCatalog,
  };
}

