import { useState } from 'preact/hooks';
import {
  generateProgram,
  type ProgramGenerationResult,
} from '../../../llm/programGen';
import type { Inventory } from '../../../data/inventory';
import type { Finding } from '../../../db/programSchema';
import type { Program } from '../types';

interface Props {
  inventory: Inventory;
  previousProgram: Program | null;
  onSave: (program: Program) => void;
  onClose: () => void;
}

type Stage = 'compose' | 'generating' | 'review' | 'error';

const PLACEHOLDER =
  'e.g. 8-week hypertrophy phase, 4 days/week upper-lower split. ' +
  'I want more posterior chain work than last phase. Last phase was a ' +
  '12-week recomposition block focused on goblet squats and pushups.';

function findingLine(f: Finding): string {
  return `${f.path}: ${f.message}`;
}

function totals(program: Program): { phaseCount: number; exerciseCount: number } {
  let exerciseCount = 0;
  for (const phase of program.phases) {
    for (const w of Object.values(phase.workouts)) {
      exerciseCount += w.exercises.length;
    }
  }
  return { phaseCount: program.phases.length, exerciseCount };
}

export function GenerateAIModal({
  inventory,
  previousProgram,
  onSave,
  onClose,
}: Props) {
  const [stage, setStage] = useState<Stage>('compose');
  const [request, setRequest] = useState('');
  const [result, setResult] = useState<ProgramGenerationResult | null>(null);
  const [errorMessage, setErrorMessage] = useState<string>('');

  async function submit() {
    const trimmed = request.trim();
    if (!trimmed) return;
    setStage('generating');
    try {
      const res = await generateProgram({
        inventory,
        userRequest: trimmed,
        previousProgram: previousProgram ?? undefined,
      });
      setResult(res);
      setStage('review');
    } catch (err) {
      setErrorMessage(err instanceof Error ? err.message : String(err));
      setStage('error');
    }
  }

  function tryAgain() {
    setStage('compose');
    setErrorMessage('');
    setResult(null);
  }

  function save() {
    if (!result) return;
    onSave(result.program);
  }

  const summary = result ? totals(result.program) : null;

  return (
    <div
      class="fixed inset-0 z-50 flex items-end justify-center bg-black/60 p-4 sm:items-center"
      role="dialog"
      aria-modal="true"
      aria-labelledby="generate-ai-title"
      data-testid="generate-ai-modal"
    >
      <div class="max-h-[90vh] w-full max-w-lg overflow-hidden rounded-[2rem] bg-flux-card shadow-flux-card">
        <div class="flex items-start justify-between gap-4 px-6 pt-6">
          <h2
            id="generate-ai-title"
            class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary"
          >
            Generate with AI
          </h2>
          <button
            type="button"
            class="-mr-2 -mt-2 rounded-full px-2 py-1 text-flux-text-tertiary hover:text-flux-text-primary"
            onClick={onClose}
            aria-label="Close"
            data-testid="generate-ai-close"
          >
            ×
          </button>
        </div>

        <div class="max-h-[70vh] overflow-y-auto px-6 pb-6 pt-4">
          {stage === 'compose' && (
            <div class="space-y-4">
              <p class="text-sm text-flux-text-secondary">
                Describe the phase you want. Mention goals, schedule
                preferences, duration, and anything to carry forward (or
                away) from your previous phase.
              </p>
              <textarea
                class="h-40 w-full resize-none rounded-2xl bg-flux-soft p-3 text-sm text-flux-text-primary placeholder:text-flux-text-tertiary focus:outline-none"
                placeholder={PLACEHOLDER}
                value={request}
                onInput={(e) =>
                  setRequest((e.target as HTMLTextAreaElement).value)
                }
                data-testid="generate-ai-request"
              />
              <div class="flex justify-end gap-2">
                <button
                  type="button"
                  class="rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
                  onClick={onClose}
                >
                  Cancel
                </button>
                <button
                  type="button"
                  class="rounded-full bg-flux-accent px-5 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-accent-fg shadow-flux-soft transition-opacity hover:opacity-90 disabled:opacity-40"
                  onClick={submit}
                  disabled={request.trim().length === 0}
                  data-testid="generate-ai-submit"
                >
                  Generate
                </button>
              </div>
            </div>
          )}

          {stage === 'generating' && (
            <div
              class="flex flex-col items-center gap-3 py-12 text-center"
              data-testid="generate-ai-loading"
            >
              <p class="text-sm text-flux-text-secondary">
                Generating program…
              </p>
              <p class="text-[10px] uppercase tracking-[0.18em] text-flux-text-tertiary">
                Big models can take 20–60 seconds.
              </p>
            </div>
          )}

          {stage === 'review' && result && summary && (
            <div class="space-y-4" data-testid="generate-ai-review">
              <div class="rounded-2xl bg-flux-soft px-4 py-3 text-xs text-flux-text-secondary">
                <span class="font-medium text-flux-text-primary">
                  {summary.phaseCount}
                </span>{' '}
                phase{summary.phaseCount === 1 ? '' : 's'} ·{' '}
                <span class="font-medium text-flux-text-primary">
                  {summary.exerciseCount}
                </span>{' '}
                exercise prescription
                {summary.exerciseCount === 1 ? '' : 's'} · filtered from{' '}
                <span class="font-medium text-flux-text-primary">
                  {result.filteredCatalog.totalCatalogSize}
                </span>{' '}
                catalog entries to{' '}
                <span class="font-medium text-flux-text-primary">
                  {result.filteredCatalog.supportedCount}
                </span>{' '}
                based on your inventory.
              </div>

              {result.warnings.length > 0 ? (
                <div class="space-y-2">
                  <p class="text-[10px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">
                    Inventory warnings
                  </p>
                  <ul class="space-y-1 text-xs text-flux-text-secondary">
                    {result.warnings.map((w, i) => (
                      <li
                        key={`${w.path}-${i}`}
                        class="rounded-2xl bg-flux-soft px-3 py-2"
                        data-testid={`generate-ai-warning-${i}`}
                      >
                        {findingLine(w)}
                      </li>
                    ))}
                  </ul>
                </div>
              ) : (
                <p class="text-xs text-flux-text-secondary">
                  No inventory warnings — every exercise matched your equipment.
                </p>
              )}

              <div class="flex justify-end gap-2">
                <button
                  type="button"
                  class="rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
                  onClick={tryAgain}
                  data-testid="generate-ai-discard"
                >
                  Discard
                </button>
                <button
                  type="button"
                  class="rounded-full bg-flux-accent px-5 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-accent-fg shadow-flux-soft transition-opacity hover:opacity-90"
                  onClick={save}
                  data-testid="generate-ai-save"
                >
                  Save program
                </button>
              </div>
            </div>
          )}

          {stage === 'error' && (
            <div class="space-y-4">
              <p
                class="rounded-2xl bg-flux-soft px-4 py-3 text-xs text-flux-text-secondary"
                data-testid="generate-ai-error"
              >
                {errorMessage || 'Generation failed.'}
              </p>
              <div class="flex justify-end gap-2">
                <button
                  type="button"
                  class="rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
                  onClick={onClose}
                >
                  Cancel
                </button>
                <button
                  type="button"
                  class="rounded-full bg-flux-accent px-5 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-accent-fg shadow-flux-soft transition-opacity hover:opacity-90"
                  onClick={tryAgain}
                  data-testid="generate-ai-retry"
                >
                  Try again
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

