  return program.phases.find((p) => p.id === state.currentPhase) ?? null;
}

function formatDriftMessage(missing: EquipmentKind[]): string {
  const names = missing.map((k) => EQUIPMENT_CATALOG[k]?.name.toLowerCase() ?? k);
