                    entry={log[key]}
                    suggestedWeight={suggested}
                    lastWeight={ex.usesWeight ? null : getLastWeight(last)}
                    allowedWeights={allowedWeights}
                    inventoryConfigured={inventoryConfigured}
                    onLog={onLog}
                    onPlayVideo={(videoId, start) => setVideo({ videoId, start })}
                  />
                </div>
              );
            })}
          </div>
        </>
      ) : (
