          <div
            class="overflow-hidden rounded-[2rem] bg-flux-card p-6 shadow-flux-card"
            data-testid="workout-card"
          >
            <p class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
