import { test, expect } from '@playwright/test';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

import { EXERCISE_CATALOG } from '../src/data/exerciseCatalog';
import { buildFilteredCatalog } from '../src/llm/filteredCatalog';
import {
  RUNTIME_START_MARKER,
  RUNTIME_END_MARKER,
  assemblePrompt,
  extractRuntimeSection,
} from '../src/llm/promptAssembly';
import { validateProgramSchema } from '../src/db/programSchema';
import type { Inventory } from '../src/data/inventory';
import type { Program } from '../src/tabs/Workouts/types';

const __dirname = dirname(fileURLToPath(import.meta.url));
const PROMPT_TEMPLATE_PATH = resolve(
  __dirname,
  '..',
  'prompts',
  'generate-phase.md',
);

function loadTemplate(): string {
  return readFileSync(PROMPT_TEMPLATE_PATH, 'utf-8');
}

function makeValidProgram(exerciseId: string): Program {
  return {
    meta: {
      startDate: '2026-01-01',
      version: 'mock',
      principles: [
        'injury_prevention',
        'mobility_every_phase',
        'form_over_load',
        'longevity_focus',
      ],
      constraints: { mobility_required: true, min_mobility_days_per_week: 1 },
    },
    phases: [
      {
        id: 'p1',
        name: 'Phase 1',
        duration_weeks: 4,
        workouts: {
          A: {
            name: 'Workout A',
            focus: 'full body',
            exercises: [
              {
                exercise_id: exerciseId,
                sets: 3,
                reps: '10',
                rest: '60s',
              },
            ],
          },
          Mobility: {
            name: 'Mobility Flow',
            focus: 'mobility',
            exercises: [
              {
                exercise_id: 'cat-cow-spinal-flow',
                sets: 2,
                reps: '10',
                rest: '30s',
              },
            ],
          },
        },
      },
    ],
  };
}

test.describe('buildFilteredCatalog', () => {
  test('empty inventory drops weighted/equipment exercises but keeps bodyweight + bodyweight-fallback ones', () => {
    const result = buildFilteredCatalog({});
    const ids = result.exercises.map((e) => e.id).sort();
    expect(ids).toEqual(
      [
        '90-90-hip-switch',
        'cat-cow-spinal-flow',
        'swedish-ladder-pushups',
        'thread-the-needle',
        'wall-slides',
        'warmup-hip-circles',
        'warmup-worlds-greatest-stretch',
      ].sort(),
    );
    expect(result.totalCatalogSize).toBe(
      Object.keys(EXERCISE_CATALOG).length,
    );
    expect(result.supportedCount).toBe(result.exercises.length);
    // None of the kettlebell entries leak through.
    expect(ids).not.toContain('kettlebell-swings');
    expect(ids).not.toContain('goblet-squats');
    expect(ids).not.toContain('kb-gorilla-rows');
    expect(ids).not.toContain('hanging-knee-raises');
    // Weighted entries that survive must have allowedWeights null (i.e. usesWeight=false).
    const weighted = result.exercises.filter((e) => e.allowedWeights !== null);
    expect(weighted).toEqual([]);
  });

  test('kettlebell-only inventory adds KB-driven exercises with the right allowedWeights', () => {
    const inv: Inventory = {
      kettlebell: { kind: 'kettlebell', ownedWeights: [25] },
    };
    const result = buildFilteredCatalog(inv);
    const ids = new Set(result.exercises.map((e) => e.id));
    expect(ids.has('goblet-squats')).toBe(true);
    expect(ids.has('kettlebell-swings')).toBe(true);
    expect(ids.has('kb-gorilla-rows')).toBe(true);
    expect(ids.has('trx-inverted-rows')).toBe(false);

    const goblet = result.exercises.find((e) => e.id === 'goblet-squats');
    expect(goblet?.allowedWeights).toEqual([25]);
    const swings = result.exercises.find((e) => e.id === 'kettlebell-swings');
    expect(swings?.allowedWeights).toEqual([25]);
    const rows = result.exercises.find((e) => e.id === 'kb-gorilla-rows');
    expect(rows?.allowedWeights).toEqual([25]);
  });

  test('KB + DB inventory unions allowedWeights for exercises with both as alternatives', () => {
    const inv: Inventory = {
      kettlebell: { kind: 'kettlebell', ownedWeights: [25, 35] },
      dumbbell: { kind: 'dumbbell', ownedWeights: [10, 15, 20] },
    };
    const result = buildFilteredCatalog(inv);
    const rows = result.exercises.find((e) => e.id === 'kb-gorilla-rows');
    expect(rows?.allowedWeights).toEqual([10, 15, 20, 25, 35]);
  });

  test('TRX + swedish-ladder + pullup-bar enables unweighted exercises only', () => {
    const inv: Inventory = {
      trx: { kind: 'trx', ownedWeights: [] },
      'swedish-ladder': { kind: 'swedish-ladder', ownedWeights: [] },
      'pullup-bar': { kind: 'pullup-bar', ownedWeights: [] },
    };
    const result = buildFilteredCatalog(inv);
    const ids = new Set(result.exercises.map((e) => e.id));
    expect(ids.has('trx-inverted-rows')).toBe(true);
    expect(ids.has('swedish-ladder-dead-hang')).toBe(true);
    expect(ids.has('swedish-ladder-pushups')).toBe(true);
    expect(ids.has('hanging-knee-raises')).toBe(true);

    // Weighted exercises absent.
    expect(ids.has('kettlebell-swings')).toBe(false);
    expect(ids.has('goblet-squats')).toBe(false);
    expect(ids.has('kb-gorilla-rows')).toBe(false);
    // None of the surviving entries should be usesWeight.
    for (const ex of result.exercises) {
      expect(ex.allowedWeights).toBeNull();
    }
  });
});

test.describe('promptAssembly', () => {
  test('extractRuntimeSection pulls only content between markers', () => {
    const raw = loadTemplate();
    expect(raw).toContain(RUNTIME_START_MARKER);
    expect(raw).toContain(RUNTIME_END_MARKER);
    const runtime = extractRuntimeSection(raw);
    expect(runtime).toContain('{{user_request}}');
    expect(runtime).toContain('{{filtered_catalog_json}}');
    expect(runtime).toContain('{{previous_program_or_none}}');
    // Manual fallback content must not leak into the runtime section.
    expect(runtime).not.toContain('Manual fallback');
    expect(runtime).not.toContain('Per-phase prompt skeletons');
  });

  test('assemblePrompt substitutes placeholders and renders catalog JSON inline', () => {
    const filtered = buildFilteredCatalog({
      kettlebell: { kind: 'kettlebell', ownedWeights: [25] },
    });
    const prompt = assemblePrompt({
      template: loadTemplate(),
      userRequest: 'I want a 6-week hypertrophy phase, 4 days/week.',
      filteredCatalog: filtered,
    });
    expect(prompt).toContain('6-week hypertrophy phase');
    expect(prompt).toContain('"id": "kettlebell-swings"');
    expect(prompt).toContain('"allowedWeights"');
    // Unsupported exercises must NOT appear in the prompt.
    expect(prompt).not.toContain('"id": "trx-inverted-rows"');
    // Previous-program placeholder defaults to none when not provided.
    expect(prompt).toContain('none');
    expect(prompt).not.toContain('{{user_request}}');
    expect(prompt).not.toContain('{{filtered_catalog_json}}');
    expect(prompt).not.toContain('{{previous_program_or_none}}');
  });

  test('assemblePrompt serializes a previous program when supplied', () => {
    const filtered = buildFilteredCatalog({});
    const prev = makeValidProgram('cat-cow-spinal-flow');
    const prompt = assemblePrompt({
      template: loadTemplate(),
      userRequest: 'next phase',
      filteredCatalog: filtered,
      previousProgram: prev,
    });
    expect(prompt).toContain('"version": "mock"');
    expect(prompt).toContain('"cat-cow-spinal-flow"');
  });
});

test.describe('generateProgram (mocked provider)', () => {
  // generateProgram lives in src/llm/programGen.ts, which imports the prompt
  // template via Vite's ?raw query string. Node-side Playwright runners
  // cannot resolve that syntax, so we drive these tests through page.evaluate
  // against the built bundle (same path the real UI takes).

  test.beforeEach(async ({ context }) => {
    await context.clearCookies();
  });

  async function setupProvider(
    page: import('@playwright/test').Page,
    generate: (prompt: string) => string,
  ) {
    await page.goto('/');
    await page.evaluate(async () => {
      await new Promise<void>((resolve) => {
        const req = indexedDB.deleteDatabase('flux-db');
        req.onsuccess = () => resolve();
        req.onerror = () => resolve();
        req.onblocked = () => resolve();
      });
    });
    await page.reload();
    await page.waitForFunction(
      () =>
        typeof (window as unknown as { flux_test_configureLLM?: unknown })
          .flux_test_configureLLM === 'function',
    );
    await page.evaluate((src) => {
      const fn = new Function('prompt', `return (${src})(prompt);`) as (
        prompt: string,
      ) => string;
      const provider = {
        id: 'mock',
        available: true,
        generate: async ({ prompt }: { prompt: string }) => {
          (
            window as unknown as { __lastPrompt?: string }
          ).__lastPrompt = prompt;
          return fn(prompt);
        },
      };
      (
        window as unknown as {
          flux_test_configureLLM: (p: unknown) => void;
        }
      ).flux_test_configureLLM(provider);
    }, generate.toString());
  }

  test('prompt sent to provider contains filtered catalog and excludes unsupported exercises', async ({
    page,
  }) => {
    const validProgram = makeValidProgram('cat-cow-spinal-flow');
    await setupProvider(page, () => JSON.stringify(validProgram));

    const out = await page.evaluate(async (programJson) => {
      const mod = await import('/src/llm/programGen.ts');
      try {
        const result = await (
          mod as unknown as {
            generateProgram: (opts: unknown) => Promise<{
              warnings: { message: string }[];
              filteredCatalog: { supportedCount: number };
            }>;
          }
        ).generateProgram({
          inventory: {},
          userRequest: 'mobility phase please',
        });
        return {
          ok: true,
          lastPrompt: (window as unknown as { __lastPrompt?: string })
            .__lastPrompt,
          warnings: result.warnings,
          supported: result.filteredCatalog.supportedCount,
          programVersion: programJson,
        };
      } catch (err) {
        return { ok: false, message: (err as Error).message };
      }
    }, validProgram.meta.version);

    expect(out.ok).toBe(true);
    expect(out.lastPrompt).toContain('mobility phase please');
    expect(out.lastPrompt).toContain('"cat-cow-spinal-flow"');
    // Unsupported (kettlebell) entries must not appear.
    expect(out.lastPrompt).not.toContain('"kettlebell-swings"');
    expect(out.warnings).toEqual([]);
  });

  test('returned program with inventory mismatch surfaces warnings', async ({
    page,
  }) => {
    // Provider returns a program referencing kettlebell-swings, but inventory is empty.
    const program = makeValidProgram('kettlebell-swings');
    await setupProvider(page, () => JSON.stringify(program));

    const out = await page.evaluate(async () => {
      const mod = await import('/src/llm/programGen.ts');
      const result = await (
        mod as unknown as {
          generateProgram: (opts: unknown) => Promise<{
            warnings: { message: string; path: string }[];
          }>;
        }
      ).generateProgram({
        inventory: {},
        userRequest: 'anything',
      });
      return result;
    });

    expect(out.warnings.length).toBeGreaterThan(0);
    expect(out.warnings[0].message).toMatch(/not in inventory/);
  });

  test('malformed JSON throws with a clear message', async ({ page }) => {
    await setupProvider(page, () => 'not json at all');

    const out = await page.evaluate(async () => {
      const mod = await import('/src/llm/programGen.ts');
      try {
        await (
          mod as unknown as {
            generateProgram: (opts: unknown) => Promise<unknown>;
          }
        ).generateProgram({ inventory: {}, userRequest: 'hi' });
        return { ok: true };
      } catch (err) {
        return { ok: false, message: (err as Error).message };
      }
    });

    expect(out.ok).toBe(false);
    expect(out.message).toContain('non-JSON');
  });

  test('structurally invalid program throws with schema details', async ({
    page,
  }) => {
    await setupProvider(page, () => '{"phases": []}');

    const out = await page.evaluate(async () => {
      const mod = await import('/src/llm/programGen.ts');
      try {
        await (
          mod as unknown as {
            generateProgram: (opts: unknown) => Promise<unknown>;
          }
        ).generateProgram({ inventory: {}, userRequest: 'hi' });
        return { ok: true };
      } catch (err) {
        return { ok: false, message: (err as Error).message };
      }
    });

    expect(out.ok).toBe(false);
    expect(out.message).toMatch(/schema validation/);
  });
});

test.describe('Generate-with-AI UI', () => {
  test.beforeEach(async ({ context }) => {
    await context.clearCookies();
  });

  test('button is disabled with a configure-in-Settings tooltip when no provider available', async ({
    page,
  }) => {
    await page.goto('/');
    await page.evaluate(async () => {
      await new Promise<void>((resolve) => {
        const req = indexedDB.deleteDatabase('flux-db');
        req.onsuccess = () => resolve();
        req.onerror = () => resolve();
        req.onblocked = () => resolve();
      });
    });
    await page.reload();
    const btn = page.getByTestId('generate-ai-btn');
    await expect(btn).toBeVisible();
    await expect(btn).toBeDisabled();
    await expect(btn).toHaveAttribute(
      'title',
      'Configure an LLM provider in Settings to enable.',
    );
  });

  test('mock provider + generate + save → program loads in Workouts', async ({
    page,
  }) => {
    const program = makeValidProgram('cat-cow-spinal-flow');

    await page.goto('/');
    await page.evaluate(async () => {
      await new Promise<void>((resolve) => {
        const req = indexedDB.deleteDatabase('flux-db');
        req.onsuccess = () => resolve();
        req.onerror = () => resolve();
        req.onblocked = () => resolve();
      });
    });
    await page.reload();

    await page.waitForFunction(
      () =>
        typeof (window as unknown as { flux_test_configureLLM?: unknown })
          .flux_test_configureLLM === 'function',
    );
    await page.evaluate((p) => {
      const provider = {
        id: 'mock-ui',
        available: true,
        generate: async () => JSON.stringify(p),
      };
      (
        window as unknown as {
          flux_test_configureLLM: (provider: unknown) => void;
        }
      ).flux_test_configureLLM(provider);
    }, program);

    const btn = page.getByTestId('generate-ai-btn');
    await expect(btn).toBeEnabled();
    await btn.click();

    await expect(page.getByTestId('generate-ai-modal')).toBeVisible();
    await page
      .getByTestId('generate-ai-request')
      .fill('6-week recomposition phase, 3 days a week');
    await page.getByTestId('generate-ai-submit').click();

    await expect(page.getByTestId('generate-ai-review')).toBeVisible();
    await page.getByTestId('generate-ai-save').click();

    // Modal closes and program loads — Workouts shows the workout card.
    await expect(page.getByTestId('generate-ai-modal')).toHaveCount(0);
    await expect(page.getByTestId('workout-name')).toBeVisible();
  });

  test('inventory mismatch shows a warning on the review screen', async ({
    page,
  }) => {
    // Provider returns kettlebell-swings, but empty inventory will trigger a warning.
    const program = makeValidProgram('kettlebell-swings');

    await page.goto('/');
    await page.evaluate(async () => {
      await new Promise<void>((resolve) => {
        const req = indexedDB.deleteDatabase('flux-db');
        req.onsuccess = () => resolve();
        req.onerror = () => resolve();
        req.onblocked = () => resolve();
      });
    });
    await page.reload();
    await page.waitForFunction(
      () =>
        typeof (window as unknown as { flux_test_configureLLM?: unknown })
          .flux_test_configureLLM === 'function',
    );
    await page.evaluate((p) => {
      const provider = {
        id: 'mock-warn',
        available: true,
        generate: async () => JSON.stringify(p),
      };
      (
        window as unknown as {
          flux_test_configureLLM: (provider: unknown) => void;
        }
      ).flux_test_configureLLM(provider);
    }, program);

    await page.getByTestId('generate-ai-btn').click();
    await page.getByTestId('generate-ai-request').fill('phase');
    await page.getByTestId('generate-ai-submit').click();

    await expect(page.getByTestId('generate-ai-review')).toBeVisible();
    await expect(page.getByTestId('generate-ai-warning-0')).toBeVisible();
    await expect(page.getByTestId('generate-ai-warning-0')).toContainText(
      'not in inventory',
    );
  });
});

test.describe('manual paste workflow still works', () => {
  test('prompts/generate-phase.md contains a manual fallback section below the runtime markers', () => {
    const raw = loadTemplate();
    const startIdx = raw.indexOf(RUNTIME_START_MARKER);
    const endIdx = raw.indexOf(RUNTIME_END_MARKER);
    expect(startIdx).toBeGreaterThan(-1);
    expect(endIdx).toBeGreaterThan(startIdx);
    const afterMarkers = raw.slice(endIdx + RUNTIME_END_MARKER.length);
    expect(afterMarkers).toContain('Manual fallback');
    expect(afterMarkers).toContain('Core principles');
    // The manual content references the same principle vocabulary we
    // enforce in code, so the paste workflow stays compatible.
    expect(afterMarkers).toContain('INJURY PREVENTION');
    expect(afterMarkers).toContain('MOBILITY IN EVERY PHASE');
  });

  test('valid program from manual flow still validates against the schema', () => {
    const program = makeValidProgram('cat-cow-spinal-flow');
    const v = validateProgramSchema(program, EXERCISE_CATALOG);
    expect(v.ok).toBe(true);
  });
});

