test.describe('promptAssembly', () => {
  test('extractRuntimeSection pulls only content between markers', () => {
    const raw = loadTemplate();
    expect(raw).toContain(RUNTIME_START_MARKER);
    expect(raw).toContain(RUNTIME_END_MARKER);
    const runtime = extractRuntimeSection(raw);
    expect(runtime).toContain('{{user_request}}');
    expect(runtime).toContain('{{filtered_catalog_json}}');
    expect(runtime).toContain('{{previous_program_or_none}}');
    // Manual fallback content must not leak into the runtime section.
    expect(runtime).not.toContain('Manual fallback');
    expect(runtime).not.toContain('Per-phase prompt skeletons');
  });

  test('assemblePrompt substitutes placeholders and renders catalog JSON inline', () => {
    const filtered = buildFilteredCatalog({
      kettlebell: { kind: 'kettlebell', ownedWeights: [25] },
    });
    const prompt = assemblePrompt({
      template: loadTemplate(),
      userRequest: 'I want a 6-week hypertrophy phase, 4 days/week.',
      filteredCatalog: filtered,
    });
    expect(prompt).toContain('6-week hypertrophy phase');
    expect(prompt).toContain('"id": "kettlebell-swings"');
    expect(prompt).toContain('"allowedWeights"');
    // Unsupported exercises must NOT appear in the prompt.
    expect(prompt).not.toContain('"id": "trx-inverted-rows"');
    // Previous-program placeholder defaults to none when not provided.
    expect(prompt).toContain('none');
    expect(prompt).not.toContain('{{user_request}}');
    expect(prompt).not.toContain('{{filtered_catalog_json}}');
    expect(prompt).not.toContain('{{previous_program_or_none}}');
  });

  test('assemblePrompt serializes a previous program when supplied', () => {
    const filtered = buildFilteredCatalog({});
    const prev = makeValidProgram('cat-cow-spinal-flow');
    const prompt = assemblePrompt({
      template: loadTemplate(),
      userRequest: 'next phase',
      filteredCatalog: filtered,
      previousProgram: prev,
    });
    expect(prompt).toContain('"version": "mock"');
    expect(prompt).toContain('"cat-cow-spinal-flow"');
  });
});

test.describe('generateProgram (mocked provider)', () => {
  // generateProgram lives in src/llm/programGen.ts, which imports the prompt
  // template via Vite's ?raw query string. Node-side Playwright runners
  // cannot resolve that syntax, so we drive these tests through page.evaluate
  // against the built bundle (same path the real UI takes).

  test.beforeEach(async ({ context }) => {
    await context.clearCookies();
  });

  async function setupProvider(
    page: import('@playwright/test').Page,
    generate: (prompt: string) => string,
  ) {
    await page.goto('/');
    await page.evaluate(async () => {
      await new Promise<void>((resolve) => {
        const req = indexedDB.deleteDatabase('flux-db');
        req.onsuccess = () => resolve();
        req.onerror = () => resolve();
        req.onblocked = () => resolve();
      });
    });
    await page.reload();
    await page.waitForFunction(
      () =>
        typeof (window as unknown as { flux_test_configureLLM?: unknown })
          .flux_test_configureLLM === 'function',
    );
    await page.evaluate((src) => {
      const fn = new Function('prompt', `return (${src})(prompt);`) as (
        prompt: string,
      ) => string;
      const provider = {
        id: 'mock',
        available: true,
        generate: async ({ prompt }: { prompt: string }) => {
          (
            window as unknown as { __lastPrompt?: string }
          ).__lastPrompt = prompt;
          return fn(prompt);
        },
      };
      (
        window as unknown as {
          flux_test_configureLLM: (p: unknown) => void;
        }
      ).flux_test_configureLLM(provider);
    }, generate.toString());
  }

  test('prompt sent to provider contains filtered catalog and excludes unsupported exercises', async ({
    page,
  }) => {
    const validProgram = makeValidProgram('cat-cow-spinal-flow');
    await setupProvider(page, () => JSON.stringify(validProgram));

    const out = await page.evaluate(async (programJson) => {
      const mod = await import('/src/llm/programGen.ts');
      try {
        const result = await (
          mod as unknown as {
            generateProgram: (opts: unknown) => Promise<{
              warnings: { message: string }[];
              filteredCatalog: { supportedCount: number };
            }>;
          }
        ).generateProgram({
          inventory: {},
          userRequest: 'mobility phase please',
        });
        return {
          ok: true,
          lastPrompt: (window as unknown as { __lastPrompt?: string })
            .__lastPrompt,
          warnings: result.warnings,
          supported: result.filteredCatalog.supportedCount,
          programVersion: programJson,
        };
      } catch (err) {
        return { ok: false, message: (err as Error).message };
      }
    }, validProgram.meta.version);

    expect(out.ok).toBe(true);
    expect(out.lastPrompt).toContain('mobility phase please');
    expect(out.lastPrompt).toContain('"cat-cow-spinal-flow"');
    // Unsupported (kettlebell) entries must not appear.
    expect(out.lastPrompt).not.toContain('"kettlebell-swings"');
    expect(out.warnings).toEqual([]);
  });

  test('returned program with inventory mismatch surfaces warnings', async ({
    page,
  }) => {
    // Provider returns a program referencing kettlebell-swings, but inventory is empty.
    const program = makeValidProgram('kettlebell-swings');
    await setupProvider(page, () => JSON.stringify(program));

    const out = await page.evaluate(async () => {
      const mod = await import('/src/llm/programGen.ts');
      const result = await (
        mod as unknown as {
          generateProgram: (opts: unknown) => Promise<{
            warnings: { message: string; path: string }[];
          }>;
        }
      ).generateProgram({
        inventory: {},
        userRequest: 'anything',
      });
      return result;
    });

    expect(out.warnings.length).toBeGreaterThan(0);
    expect(out.warnings[0].message).toMatch(/not in inventory/);
  });

  test('malformed JSON throws with a clear message', async ({ page }) => {
    await setupProvider(page, () => 'not json at all');

    const out = await page.evaluate(async () => {
      const mod = await import('/src/llm/programGen.ts');
      try {
        await (
          mod as unknown as {
            generateProgram: (opts: unknown) => Promise<unknown>;
          }
        ).generateProgram({ inventory: {}, userRequest: 'hi' });
        return { ok: true };
      } catch (err) {
        return { ok: false, message: (err as Error).message };
      }
    });

    expect(out.ok).toBe(false);
    expect(out.message).toContain('non-JSON');
  });

  test('structurally invalid program throws with schema details', async ({
    page,
  }) => {
    await setupProvider(page, () => '{"phases": []}');

    const out = await page.evaluate(async () => {
      const mod = await import('/src/llm/programGen.ts');
      try {
        await (
          mod as unknown as {
            generateProgram: (opts: unknown) => Promise<unknown>;
          }
        ).generateProgram({ inventory: {}, userRequest: 'hi' });
        return { ok: true };
      } catch (err) {
        return { ok: false, message: (err as Error).message };
      }
    });

    expect(out.ok).toBe(false);
    expect(out.message).toMatch(/schema validation/);
  });
});

